mapper.select:
SELECT collect_time, value
FROM metric_data_1m
WHERE instance_id = #{instanceId}
  AND metric_code = #{metricCode}
  AND collect_time >= #{from}
  AND collect_time <= #{to}
ORDER BY collect_time ASC
LIMIT 2000

SELECT collect_time, value
FROM metric_data_1h
WHERE instance_id = #{instanceId}
  AND metric_code = #{metricCode}
  AND collect_time >= #{from}
  AND collect_time <= #{to}
ORDER BY collect_time ASC
LIMIT 2000

SELECT bucket AS collect_time, avg_value AS value
FROM metric_data_1h_cagg
WHERE instance_id = #{instanceId}
  AND metric_code = #{metricCode}
  AND bucket >= #{from}
  AND bucket <= #{to}
ORDER BY bucket ASC
LIMIT 2000

SELECT date_trunc('hour', collect_time) AS collect_time, avg(value) AS value
FROM metric_data_1m
WHERE instance_id = #{instanceId}
  AND metric_code = #{metricCode}
  AND collect_time >= #{from}
  AND collect_time <= #{to}
GROUP BY date_trunc('hour', collect_time)
ORDER BY 1 ASC
LIMIT 2000
